mapper.select:
SELECT c1.business_type As businessType, r.product_name AS productName, r.brand_number AS brandNumber, r.factory_id AS factoryId, r.factory_name AS factoryName, r.buy_company_id AS buyCompanyId, r.buy_company_name AS buyCompanyName, bp.deal_price AS buyPrice, bp.deal_number As buyTotalNumber,
r.deal_number*bp.deal_price As buyTotalAmount, (c1.total_amount - IFNULL(c1.billed_amount, 0)) AS invoiceBillAmount, r.sell_company_id AS sellCompanyId, r.sell_company_name AS sellCompanyName, sp.deal_price AS sellPrice, sp.deal_number AS sellTotalNumber, sp.total_price AS sellTotalAmount, (c2.total_amount - IFNULL(c2.billed_amount, 0)) AS receiveBillAmount, c1.id As buyId, c2.id As sellId, c1.contract_no As buyContractNo, c1.source As source, c1.our_company_name As ourCompanyName, c1.contract_time As buyContractDate, c1.bill_flg As billFlg, c1.match_user_name As buyMatchUserName, c2.contract_no As sellContractNo, c2.match_user_name As sellMatchUserName, sp.warehouse_number As warehouseNumber, c2.contract_time As sellContractDate, r.id As relaId, t.content As sellContent, t1.content As buyContent, c2.credit_flg As creditFlg, c2.pay_full_time As piccAccrualDate, c2.delivery_date_from As piccHappenDate, c2.total_amount As piccTotalAmount, c2.total_number As piccTotalNumber, c2.match_user_id As sellMatchUserId, c1.match_user_id As buyMatchUserId, r.deal_number As dealNumber, c2.enterprise_id As enterpriseId, c2.status As status, 'bas' As appCode, sp.settlement_code As settlementNo FROM t_ctr_contract_rela r LEFT JOIN t_ctr_contract c1 ON c1.id = r.buy_contract_id LEFT JOIN t_ctr_contract c2 ON c2.id = r.sell_contract_id LEFT JOIN t_ctr_product bp ON bp.id = r.buy_product_id LEFT JOIN t_ctr_product sp ON sp.id = r.sell_product_id LEFT JOIN t_ctr_contract_text t on t.ctr_contract_id = c2.id LEFT JOIN t_ctr_contract_text t1 on t1.ctr_contract_id = c1.id WHERE 1=1 AND c2.contract_no = #{sellContractNo}
AND c1.enterprise_id = #{enterpriseId}
